<?php
namespace App\Controllers;
use App\Core\View;
final class InstallerController
{
 public function index():void{if(is_file(dirname(__DIR__,2).'/storage/installed.lock'))redirect('/login');View::render('install/index',['title'=>'Install Rock Bluffs Portal'],'auth');}
 public function install():void{verify_csrf();$root=dirname(__DIR__,2);if(is_file($root.'/storage/installed.lock'))redirect('/login');$env="APP_NAME=\"Rock Bluffs Exterior Services\"\nAPP_ENV=production\nAPP_URL=".trim($_POST['app_url'])."\nAPP_TIMEZONE=America/Chicago\nSESSION_SECURE=true\nDB_HOST=".trim($_POST['db_host'])."\nDB_PORT=3306\nDB_DATABASE=".trim($_POST['db_database'])."\nDB_USERNAME=".trim($_POST['db_username'])."\nDB_PASSWORD=\"".str_replace('"','\\"',(string)$_POST['db_password'])."\"\n";file_put_contents($root.'/.env',$env);\App\Core\Env::load($root.'/.env');try{$pdo=\App\Core\Database::connection();$sql=file_get_contents($root.'/database/schema.sql');$sql=preg_replace('/^\s*(USE|SOURCE)\b.*;\s*$/mi','',$sql);foreach(preg_split('/;\s*(?:\r?\n|$)/',$sql)?:[] as $s){$s=trim($s);if($s===''||str_starts_with($s,'--'))continue;try{$pdo->exec($s);}catch(\PDOException $e){if(!str_contains($e->getMessage(),'already exists')&&!str_contains($e->getMessage(),'Duplicate'))throw $e;}}$pdo->prepare('INSERT INTO users(name,email,password_hash,role,status) VALUES(?,?,?,?,?)')->execute([trim($_POST['admin_name']),strtolower(trim($_POST['admin_email'])),password_hash((string)$_POST['admin_password'],PASSWORD_DEFAULT),'administrator','active']);if(!is_dir($root.'/storage'))mkdir($root.'/storage',0770,true);file_put_contents($root.'/storage/installed.lock',date(DATE_ATOM));flash('success','Installation complete. Sign in with the administrator account.');redirect('/login');}catch(\Throwable $e){@unlink($root.'/.env');flash('danger','Installation failed: '.$e->getMessage());redirect('/install');}}
}
